mapper.update:
update assistant_sessions
set last_message_at = #{lastMessageAt},
    updated_at = #{lastMessageAt}
where id = #{sessionId}
  and user_id = #{userId}
  and status <> 'DELETED'

update assistant_sessions
set title = #{title},
    updated_at = #{updatedAt}
where id = #{sessionId}
  and user_id = #{userId}
  and status <> 'DELETED'

mapper.delete:
delete from assistant_sessions
where id = #{sessionId}
  and user_id = #{userId}
